import { describe, expect, it } from 'vitest';
import { runClassicalStyleTransfer } from '../src/style-transfer-classical';
import {
  buildEffectiveGateMap,
  compositeStyleTransferFoldScore,
  effectiveGateAtPixel,
} from '../src/style-transfer-mesh-gate';

describe('style-transfer-mesh-gate', () => {
  it('effectiveGateAtPixel is monotone in topologyAlpha when others fixed', () => {
    const w = 0.8;
    const low = effectiveGateAtPixel(w, 0.2, undefined, undefined);
    const high = effectiveGateAtPixel(w, 0.9, undefined, undefined);
    expect(high).toBeGreaterThan(low);
    expect(low).toBeCloseTo(0.16, 5);
    expect(high).toBeCloseTo(0.72, 5);
  });

  it('buildEffectiveGateMap multiplies depth when provided', () => {
    const n = 4;
    const wave = Float32Array.from({ length: n }, () => 1);
    const topo = Float32Array.from({ length: n }, () => 0.5);
    const depth = Float32Array.from({ length: n }, () => 0.5);
    const g = buildEffectiveGateMap({ pixelCount: n, alphaWave: wave, topologyAlpha: topo, depthConfidence: depth });
    for (let i = 0; i < n; i++) expect(g[i]).toBeCloseTo(0.25, 5);
  });

  it('more restrictive topology reduces delta vs content on classical path', () => {
    const w = 8;
    const h = 8;
    const n = w * h;
    const ch = 3;
    const len = n * ch;
    const content = new Float32Array(len);
    const style = new Float32Array(len);
    for (let i = 0; i < len; i++) {
      content[i] = 0.2;
      style[i] = 0.9;
    }
    const alphaWave = { enabled: false, edgeThreshold: 0.22, edgeBoost: 0.7, frequency: 2.2, phase: 0 };
    const looseTopo = new Float32Array(n);
    looseTopo.fill(1);
    const tightTopo = new Float32Array(n);
    tightTopo.fill(0.15);
    const base = {
      content,
      style,
      width: w,
      height: h,
      channels: ch as 1 | 3,
      strength: 0.9,
      structurePreservation: 0,
      alphaWave,
      sharpen: false,
    };
    const a = runClassicalStyleTransfer({
      ...base,
      meshGate: {
        topologyAlpha: looseTopo,
        topologySource: 'stub',
        topologyProvenanceFragment: { t: 'loose' },
        depthProvenanceFragment: { d: 'none' },
      },
    });
    const b = runClassicalStyleTransfer({
      ...base,
      meshGate: {
        topologyAlpha: tightTopo,
        topologySource: 'stub',
        topologyProvenanceFragment: { t: 'tight' },
        depthProvenanceFragment: { d: 'none' },
      },
    });
    let sumDiffLoose = 0;
    let sumDiffTight = 0;
    for (let i = 0; i < len; i++) {
      sumDiffLoose += Math.abs(a.stylized[i]! - content[i]!);
      sumDiffTight += Math.abs(b.stylized[i]! - content[i]!);
    }
    expect(sumDiffTight).toBeLessThan(sumDiffLoose);
    expect(a.meshProvenance?.mean_effective_gate).toBeGreaterThan(b.meshProvenance?.mean_effective_gate ?? 0);
  });

  it('compositeStyleTransferFoldScore penalizes low topology mean', () => {
    const base = 0.1;
    const hiTopo = {
      mean_topology_alpha: 0.95,
      mean_depth_confidence: 1,
      mean_effective_gate: 0.9,
      gate_violation_score: 0.1,
    };
    const loTopo = {
      mean_topology_alpha: 0.1,
      mean_depth_confidence: 1,
      mean_effective_gate: 0.2,
      gate_violation_score: 0.8,
    };
    const sHi = compositeStyleTransferFoldScore(base, hiTopo, { topology: 0.5, depth: 0 });
    const sLo = compositeStyleTransferFoldScore(base, loTopo, { topology: 0.5, depth: 0 });
    expect(sLo).toBeGreaterThan(sHi);
  });
});
